SELECT COUNT(DISTINCT spp_code) AS distinct_species_count
FROM species_distribution
WHERE country = 'Canada';

SELECT COUNT(*) AS distribution_count
FROM species_distribution
WHERE country = 'Canada';

SELECT change_type, COUNT(*) AS change_count
FROM taxonomic_changes
GROUP BY change_type;

SELECT country, region, COUNT(spp_code) AS species_count
FROM species_distribution
GROUP BY country, region;
